```plantuml
@startuml

class User {
  -id: integer
  -name: string
  +getId(): integer
  +getName(): string
}

class Employee {
  -position: string
  +getPosition(): string
}

class Owner {
  -balance: integer
  +getBalance(): integer
}

interface StoreInterface {
  +getStoreName(): string
  +getOwnerName(): string
  +getEmployees(): []Employee
}

class CakeStore {
  -storeName: string
  -owner: Owner
  -employees: []Employee
}

class CoffeeStore {
  -storeName: string
  -owner: Owner
  -employees: []Employee
}

class MainStore {
  +storeInterface: StoreInterface
}

Employee --|> User
Owner --|> User

CakeStore o-- Employee
CakeStore *-- Owner

CoffeeStore *-- Employee
CoffeeStore o-- Owner

CakeStore ..|> StoreInterface
CoffeeStore ..|> StoreInterface

MainStore --> StoreInterface

@enduml
```
